To achieve one index cache per index file, you can create a separate cache instance for each index file. This way, when you remove old index files, the corresponding cache instances will also be removed, avoiding any potential memory leaks or issues with expired data.

Here's a simple example using Python and the `joblib` library for caching:

```python
import joblib
import os

class IndexCache:
    def __init__(self, index_file_path):
        self.index_file_path = index_file_path
        self.cache_path = os.path.join(os.path.dirname(index_file_path), 'index_cache.joblib')

    def get(self, key):
        try:
            return joblib.load(self.cache_path)[key]
        except KeyError:
            return None

    def set(self, key, value):
        cache = joblib.load(self.cache_path) if os.path.exists(self.cache_path) else {}
        cache[key] = value
        joblib.dump(cache, self.cache_path)

    def delete(self, key):
        cache = joblib.load(self.cache_path) if os.path.exists(self.cache_path) else {}
        if key in cache:
            del cache[key]
            joblib.dump(cache, self.cache_path)

